102	export function SignupForm() {
103	  const router = useRouter();
104	
105	  const checkEmailExists = useCheckEmailExists();
106	  const checkPhoneExists = useCheckPhoneExists();
107	
108	  const form = useForm<SignupFormData>({
109	    resolver: zodResolver(signupSchema),
110	    defaultValues: {
111	      firstName: "",
112	      lastName: "",
113	      email: "",
114	      phone: "",
115	      uaeResident: false,
116	    },
117	  });
118	
119	  const { isSubmitting } = form.formState;
120	
121	  const onSubmit = async (data: SignupFormData) => {
122	    try {
123	      const [emailCheckResult, phoneCheckResult] = await Promise.all([
124	        checkEmailExists.mutateAsync(data.email),
125	        checkPhoneExists.mutateAsync(data.phone),
126	      ]);
127	
128	      let hasErrors = false;
129	
130	      if (emailCheckResult.exists) {
131	        form.setError("email", {
132	          type: "manual",
133	          message:
134	            "This email is already registered. Please use a different email or sign in.",
135	        });
136	        hasErrors = true;
137	      }
138	
139	      if (phoneCheckResult.exists) {
140	        form.setError("phone", {
141	          type: "manual",
142	          message:
143	            "This phone number is already registered. Please use a different number or sign in.",
144	        });
145	        hasErrors = true;
146	      }
147	
148	      if (hasErrors) {
149	        return;
150	      }
151	
152	      const otpResponse = await sendOtp({
153	        email: data.email,
154	        phone: data.phone,
155	        type: OtpType.SIGN_UP,
156	      });
157	
158	      authStorage.signup.set({
159	        email: data.email,
160	        phone: data.phone,
161	        firstName: data.firstName,
162	        lastName: data.lastName,
163	        role: USER_ROLES.SELLER,
164	        referralCode: undefined,
165	        devEmailOtp: otpResponse.otp,
166	        devPhoneOtp: otpResponse.otp,
167	      });
168	
169	      if (otpResponse.otp) {
170	        toast.success("OTP Generated", {
171	          description: "Check the verification page for your OTP codes",
172	        });
173	      } else {
174	        toast.success("OTP Sent", {
175	          description: "Please check your email and phone for OTP codes",
176	        });
177	      }
178	
179	      router.push(APP_ROUTES.AUTH.VERIFY_OTP);
180	    } catch {
181	      toast.error("Failed to Send OTP", {
182	        description: "Please try again later",
183	      });
184	    }
185	  };
186	
187	  return (
