192	          Join LuxFlow
193	        </h1>
194	        <p className="text-base leading-[150%] tracking-[-0.01em]">
195	          Get valuations, manage your offers, and unlock liquidity for your
196	          luxury items.
197	        </p>
198	      </div>
199	
200	      {/* Social Buttons */}
201	      <div className="flex flex-col gap-2 sm:flex-row">
202	        {SOCIAL_BUTTONS.map(({ key, Icon, label }) => (
203	          <button
204	            key={key}
205	            type="button"
206	            disabled
207	            className="flex h-12 w-full cursor-not-allowed items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] opacity-70 sm:flex-1"
208	          >
209	            <Icon />
210	            <span className="whitespace-nowrap">{label}</span>
211	          </button>
